('LP65PGGP', '546274', 'WBG - Swellendam', 80, 79.00, '2026-02-13 09:48:00', 1369.97, 'CPT - TRANSIT')
) AS t(RegistrationNumber, CardNumber, DepotName, AllocationLitres, LitresUsed, TransactionDate, AmountSpent, DepotAssignment)
LEFT JOIN Vehicles v ON v.RegistrationNumber = t.RegistrationNumber;

PRINT 'February 2026 fuel transactions imported.';
GO

-- Show import summary
SELECT 
    'Total Transactions' as Metric, 
    COUNT(*) as Value 
FROM FuelTransactions WHERE ReportMonth = 2 AND ReportYear = 2026
UNION ALL
SELECT 
    'Matched to Vehicles', 
    COUNT(*) 
FROM FuelTransactions WHERE ReportMonth = 2 AND ReportYear = 2026 AND VehicleId IS NOT NULL
UNION ALL
SELECT 
    'Unmatched', 
    COUNT(*) 
FROM FuelTransactions WHERE ReportMonth = 2 AND ReportYear = 2026 AND VehicleId IS NULL
UNION ALL
SELECT 
    'Unique Vehicles', 
    COUNT(DISTINCT RegistrationNumber) 
FROM FuelTransactions WHERE ReportMonth = 2 AND ReportYear = 2026;
GO

-- Show per-vehicle summary
SELECT TOP 10
    f.RegistrationNumber,
    f.DepotAssignment,
    COUNT(*) as Transactions,
    CAST(SUM(f.LitresUsed) AS DECIMAL(10,0)) as TotalLitres,
    CAST(SUM(f.AmountSpent) AS DECIMAL(10,2)) as TotalSpent
FROM FuelTransactions f
WHERE f.ReportMonth = 2 AND f.ReportYear = 2026
GROUP BY f.RegistrationNumber, f.DepotAssignment
ORDER BY TotalSpent DESC;
GO
